CustomField.formula:
OR(
   $Profile.Name = "STL CDA Internal Grant Admin",
   AND(
   NOT(
   AND(
   Application_Returned__c = TRUE,
   TEXT(Status__c) <> "Submitted"
      )
      ),
   OR(
      TEXT(Status__c) = "Submitted",
      TODAY() > DATEVALUE(Reference_Application__r.End_Date__c)
      )
     )
)
